\textit{Source: [FYZ], \S1.1, footnote 1.}
  A map \(a : \cE \to \sigma^* \cE^\vee\) of coherent sheaves on \(X'\) is
  \emph{Hermitian} if \(\sigma^* a^\vee = a\). We say \(a\) is \emph{injective}
  (also called \emph{non-singular}) if it is injective as a map of coherent sheaves.

\textit{Source: [FYZ], \S1.1.}
  For integers \(n \geq 1\) and \(r \geq 0\), the moduli stack \(\Sht_{\U(n)}^r\)
  parametrizes rank-\(n\) Hermitian shtukas with \(r\) legs: data consisting of
  \begin{enumerate}
    \item legs \(x'_i \in X'(S)\) for \(i = 1, \ldots, r\);
    \item rank-\(n\) Hermitian vector bundles \(\cF_0, \ldots, \cF_r\) on
      \(X' \times S\), each with Hermitian structure \(h_i : \cF_i \xrightarrow{\sim}
      \sigma^* \cF_i^\vee\);
    \item elementary modifications
      \(\cF_{i-1} \dashrightarrow \cF_i\) (lower of length 1 at \(x'_i\), upper of
      length 1 at \(\sigma(x'_i)\)) compatible with the Hermitian structures;
    \item an isomorphism \(\varphi : \cF_r \cong {}^{\tau}\!\cF_0\) compatible with
      the Hermitian structures.
  \end{enumerate}
  There is a natural forgetful map \(\Sht_{\U(n)}^r \to (X')^r\) sending a shtuka to
  its legs.

\textit{Source: [FYZ], \S1.1.}
  If \(a : \cE \to \sigma^* \cE^\vee\) is injective and \(\rank(\cE) = n\), then
  \(\cZ_{\cE}^r(a)\) is proper over \(\mathbf{F}_q\).

\textit{Source: [FYZ], \S1.1 and \S2.}
  The \emph{normalized Fourier coefficient}
  \(\widetilde{E}_a(m(\cE), s, \Phi)\) is the \(a\)-th Fourier coefficient of \(E\),
  evaluated at \(m(\cE) \in M_n(\BA)\) (the Levi element corresponding to the rank-\(n\)
  bundle \(\cE\)), and multiplied by certain normalization factors specified in \S2 of
  the paper. In this normalization, \(s = 0\) is the center of the functional equation.

\textit{Source: [FYZ], Theorem~1.1.}
  Let \(n \geq 1\) and \(r \geq 0\). Let \(\cE\) be a rank-\(n\) vector bundle on
  \(X'\) and \(a : \cE \to \sigma^* \cE^\vee\) an injective Hermitian map. Then
  \[
    \frac{1}{(\log q)^r}
    \left(\frac{d}{ds}\right)^r\!\Bigg|_{s=0}
    \!\bigl(q^{d s}\,\widetilde{E}_a(m(\cE), s, \Phi)\bigr)
    \;=\; \deg[\cZ_{\cE}^r(a)],
  \]
  where \(d = d(\cE) = -\deg(\cE) + n\deg\om_X\) (see Definition~\ref{def:central-value-d}).

\textit{Source: [FYZ], \S1 Notation.}
  A smooth, proper, geometrically connected curve \(X\) over \(k = \mathbf{F}_q\) of
  odd characteristic \(p \neq 2\), equipped with:
  \begin{itemize}
    \item canonical bundle \(\om_X\) (the line bundle of 1-forms);
    \item function field \(F = k(X)\);
    \item adèle ring \(\BA = \BA_F\);
    \item set of closed points \(|X|\);
    \item for each \(v \in |X|\): completed local ring \(\cO_v\) with fraction field
      \(F_v\), residue field \(k_v\), degree \(\deg(v) = [k_v:k]\),
      \(q_v = q^{\deg(v)} = \#k_v\), uniformizer \(\varpi_v\), and absolute value
      \(|\cdot|_v : F_v^\times \to q_v^{\mathbb{Z}}\) normalized by
      \(|\varpi_v|_v = q_v^{-1}\).
  \end{itemize}

\textit{Source: [FYZ], \S2.1.}
  The \emph{degenerate principal series}
  \[
    I_n(s, \chi) = \Ind_{P_n(\BA)}^{H_n(\BA)}
      \bigl(\chi \cdot |\cdot|_{F'}^{s + n/2}\bigr), \quad s \in \mathbf{C},
  \]
  is the unnormalized smooth induction.

\textit{Source: Feng--Yun--Zhang [MR4689373], Proposition~``KR cycle proper''.}
  Let \(a : \cE \to \sigma^*\cE^\vee\) be injective. The algebraic stack
  \(\cZ_{\cE}^r(a)\) is proper over \(\mathrm{Spec}(\mathbf{F}_q)\).

\textit{Source: Feng--Yun--Zhang [MR4689373], \S\S9--10.}
  For any two good framings \(\phi_1, \phi_2\) of \((\cE, a)\), the virtual fundamental
  classes they define in \(\Ch_0(\cZ_{\cE}^r(a))_{\mathbf{Q}}\) are equal.

\textit{Source: Feng--Yun--Zhang [MR4689373], \S4.2--4.3.}
  There is a canonical \(W_d\)-equivariant decomposition
  \[
    \mathrm{Spr}^{\mathrm{Herm}}_{2d}
    \;\cong\;
    \bigoplus_{\chi \in \mathrm{Irr}(W_d)}
    V_\chi \otimes_{\Ql} \mathrm{IC}_\chi
  \]
  in \(\mathrm{Perv}(\Herm_{2d}(X'/X), \Ql)\), where:
  \begin{itemize}
    \item \(\mathrm{Irr}(W_d)\) is the set of irreducible \(\Ql\)-representations of
      \(W_d\), parameterized by bipartitions \((\lambda, \mu)\) with
      \(|\lambda| + |\mu| = d\);
    \item \(V_\chi\) is the underlying \(\Ql\)-vector space of the irreducible
      representation \(\chi\) of \(W_d\);
    \item \(\mathrm{IC}_\chi\) is the intersection cohomology complex on
      \(\Herm_{2d}(X'/X)\) associated to the \(\chi\)-isotypical local system on
      the open stratum.
  \end{itemize}
  The multiplicity of \(\mathrm{IC}_\chi\) in \(\mathrm{Spr}^{\mathrm{Herm}}_{2d}\)
  is \(\dim_{\Ql} V_\chi\).

\textit{Source: Feng--Yun--Zhang [MR4689373], Def.~``Kd''; proof of the matching proposition.}
  Under Springer theory, the graded perverse sheaf \(\cK_d^{\mathrm{Int}}(T)
  = \bigoplus_{i=0}^d \mathrm{Spr}^{\mathrm{Herm}}_{2d}[\rho_i]\,T^i\)
  (Definition~\ref{def:K-Int}) corresponds to the graded virtual
  \(W_d\)-representation
  \[
    \rho_{\cK_d^{\mathrm{Int}}}(T)
    \;=\;
    \sum_{i=0}^{d} \Ind_{W_i \times W_{d-i}}^{W_d}
      \bigl(\chi_i \boxtimes \mathbf{1}\bigr)\, T^{i}
    \;\in\; R(W_d),
  \]
  where \(\chi_i\) is the virtual character of \(W_i\) given by the matching identity
  \(\chi_i = \sum_{j=0}^{i}(-1)^j \Ind_{S_{i-j}\times W_j}^{W_i}
  (\mathbf{1}\boxtimes\overline{\sgn}_j)\).

\textit{Source: Feng--Yun--Zhang [MR4689373], \S16.1--16.2.}
  Let \(d \geq 0\) and \(\cQ \in \Herm_{2d}(\mathbf{F}_q)\). Using the graded
  Frobenius trace formula~\ref{thm:trace-Eis}, the \(r\)-th normalized logarithmic
  \(s\)-derivative at \(s = 0\) satisfies:
  \begin{align*}
    &\frac{1}{(\log q)^r}
    \Bigl(\frac{d}{ds}\Bigr)^r\!\Bigg|_{s=0}
    \!\bigl(q^{ds}\,\widetilde{E}_a(m(\cE), s, \Phi)\bigr)
    \\
    &\quad=
    \frac{1}{(\log q)^r}
    \Bigl(\frac{d}{ds}\Bigr)^r\!\Bigg|_{s=0}
    \Biggl(
      q^{ds} \sum_{i=0}^d
      \Tr\!\bigl(\Frob_q,\; (\cK^{\mathrm{Eis}}_{d,i})_{\overline{\cQ}}\bigr)\,
      q^{-2is}
    \Biggr)
    \\
    &\quad=
    \sum_{i=0}^d
    \Tr\!\bigl(\Frob_q,\; (\cK^{\mathrm{Eis}}_{d,i})_{\overline{\cQ}}\bigr)\cdot
    (d - 2i)^r.
  \end{align*}
  The last step uses the identity
  \(\frac{1}{(\log q)^r}(\frac{d}{ds})^r|_{s=0}(q^{(d-2i)s}) = (d-2i)^r\).

\textit{Source: Feng--Yun--Zhang [MR4689373], \S16.3.}
  The higher Siegel--Weil formula (Theorem~\ref{thm:higher-siegel-weil}) holds:
  \[
    \frac{1}{(\log q)^r}
    \left(\frac{d}{ds}\right)^r\!\Bigg|_{s=0}
    \!\bigl(q^{d s}\,\widetilde{E}_a(m(\cE), s, \Phi)\bigr)
    \;=\; \deg[\cZ_{\cE}^r(a)].
  \]
